    {
        var errors = new Dictionary<string, string>();

        if (review.ReviewTitle.Contains("spam", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(review.ReviewTitle)] = "Review title contains inappropriate language.";
        }

        // Stub: additional server-side rules would go here.

        return Task.FromResult(errors);
    }
}

