+    private const long MaxFileSize = 5 * 1024 * 1024; // 5 MB
+    private const int MaxPhotoCount = 3;
+    private static readonly string[] AllowedExtensions = [".jpg", ".jpeg", ".png"];
+
+    private ReviewModel model = new();
+    private List<PhotoFile> uploadedPhotos = new();
+    private Dictionary<string, string> serverErrors = new();
+    private string? photoError;
+    private bool isSubmitting;
+    private bool submitSuccess;
+
+    private async Task OnPhotosSelected(InputFileChangeEventArgs e)
+    {
+        photoError = null;
+
+        if (e.FileCount > MaxPhotoCount)
+        {
+            photoError = $"You can upload at most {MaxPhotoCount} photos.";
+            return;
+        }
+
+        var newPhotos = new List<PhotoFile>();
+
+        foreach (var file in e.GetMultipleFiles(MaxPhotoCount))
+        {
+            var ext = Path.GetExtension(file.Name).ToLowerInvariant();
+            if (!AllowedExtensions.Contains(ext))
+            {
+                photoError = $"'{file.Name}' is not a supported format. Only JPG and PNG are allowed.";
+                return;
+            }
+
+            if (file.Size > MaxFileSize)
+            {
+                photoError = $"'{file.Name}' exceeds the 5 MB limit.";
+                return;
+            }
+
+            using var stream = file.OpenReadStream(maxAllowedSize: MaxFileSize);
+            using var ms = new MemoryStream();
+            await stream.CopyToAsync(ms);
+
+            newPhotos.Add(new PhotoFile
+            {
+                FileName = file.Name,
+                Size = file.Size,
+                Content = ms.ToArray()
+            });
+        }
+
+        uploadedPhotos = newPhotos;
+    }
+
+    private async Task HandleSubmit()
+    {
+        serverErrors.Clear();
+        isSubmitting = true;
+
+        try
+        {
+            var errors = await ReviewService.ValidateAndSubmitAsync(model, uploadedPhotos);
+
+            if (errors.Count > 0)
+            {
+                serverErrors = errors;
+            }
+            else
+            {
+                submitSuccess = true;
+            }
+        }
+        finally
+        {
+            isSubmitting = false;
+        }
+    }
